INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'overview', 'Overview > NIT Jamshedpur is located in Adityapur, District Saraikela Kharsawan, Jamshedpur, Jharkhand 831014.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'hostels_boys', 'Hostels Boys > Hostel I is for 2nd year students with single occupancy.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'hostels_boys', 'Hostels Boys > Hostel L is for 1st year, PG, and PhD students. Double sharing for 1st years, single for PhD/PG.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'hostels_boys', 'Hostels Boys > Hostels E, F, G, H are for 2nd year students with single occupancy.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'hostels_girls', 'Hostels Girls > Girls hostels: Hostel A, Hostel B, Hostel C, Hostel D, Rani Laxmi Bai, Ambedkar Hall of Residence.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > B.Tech tuition fee for General/OBC is Rs 62,500 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > B.Tech tuition fee is free (Rs 0) for SC/ST/PH students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Institute fees are Rs 12,500 per semester for all students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Hostel fees are Rs 15,000 per semester (room rent Rs 6000, maintenance Rs 7000, electricity Rs 1500, water Rs 500).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Mess advance is Rs 18,000 per semester (tentative, adjusted at actual).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > One-time payment at admission is Rs 17,000 (caution money Rs 10,000 refundable, alumni Rs 2,000, innovation project Rs 5,000).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Total first semester for General: approximately Rs 1,25,000. Subsequent semesters: Rs 1,08,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Total first semester for SC/ST: approximately Rs 62,500. Subsequent semesters: Rs 45,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Students with family income below Rs 1 lakh get full tuition fee waiver.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fee_structure', 'Fee > Students with family income Rs 1-5 lakh get 2/3rd tuition fee waiver.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Mess advance is Rs 18,000 per semester (tentative).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Daily breakfast: Bread 6 pcs, jam and butter, milk or tea, banana or egg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Monday dinner: Veg Korma or Chicken Butter Masala (4 pcs).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Thursday breakfast: Idli + Vada (4 pcs) with Sambhar and Chutney.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Thursday snacks: Litti Chokha (2 pcs) with chutney and coffee.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'mess', 'Mess > Friday snacks: Samosa with Aloo Matar and tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'wifi', 'WiFi > WiFi and LAN are both available at NIT Jamshedpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'attendance', 'Attendance > 75% attendance is mandatory at NIT Jamshedpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'clubs', 'Clubs > Clubs at NIT Jamshedpur: Qnite, Phocus, Phoenix, Rooh, LDS, Quod Invicta, Faces, Aahwan.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fests', 'Fests > Culfest is the cultural fest held in February-March.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fests', 'Fests > Ojass is the techno-management fest held in February-March.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fests', 'Fests > Urja is the sports fest held in October-November.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'canteen', 'Canteen > Canteens on campus: Amba, Annapurna, Nescafe, Continental. Night canteens are available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'restaurants', 'Restaurants > Nearby: Just Chill, Hungry Kya, The Lion Restaurant, Blue Diamond.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'restaurants', 'Restaurants > Swiggy, Zomato and all food delivery apps are available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'transport', 'Transport > Nearest airport: Birsa Munda Airport, Ranchi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'transport', 'Transport > Nearest railway station: Tatanagar Railway Station.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'transport', 'Transport > Nearest bus stand: Mango Bus Stand.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'tourist_places', 'Tourist > Dalma Wildlife Sanctuary, Dimna Lake, Jubilee Park, Tata Zoo, Chandil Dam, Bhuvneshwari Temple.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'malls', 'Malls > P N M Mall, Bindal Mall, V Mart, V2, Nagaramal Mall.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'climate', 'Climate > NIT Jamshedpur has a tropical climate with scorching summers, heavy monsoon rains, and mild pleasant winters.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'language', 'Language > Languages at NIT Jamshedpur: Hindi, English, Bengali, and Santhali.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'laundry', 'Laundry > No washing machines in hostels but washing facilities are available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'elections', 'Elections > Student council positions: President, Vice-President, General Secretary, Joint Secretary, Technical Secretary, Cultural Secretary, Sports Secretary, Club Secretary.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'shops', 'Shops > Nearby: NIT Store, Sudha Milk Parlour, Basti Shops.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fines', 'Fines > Serious misconduct: Rs 20,000-30,000. Hostel expulsion: Rs 30,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fines', 'Fines > Ragging fine: approximately Rs 20,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'fines', 'Fines > Minor offences: Rs 2,000. Late registration: Rs 1,000. Delayed fee: Rs 2,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'gym', 'Gym > NIT Gymkhana is free for students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'gym', 'Gym > Paid options nearby: Fitness Factory, Tiger Hill Gym, Golds Gym.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'medical', 'Medical > NIT Dispensary on campus with ambulances available at any time for emergencies.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'medical', 'Medical > Nearby hospitals: Meditrina Hospital, SaveLife Hospital, ESIC Hospital.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'timetable', 'Timetable > Class timings: 8:30 AM to 5:55 PM. Lunch break: 12:30 PM to 2:00 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Jamshedpur', 'timetable', 'Timetable > Lab classes have 3 groups: G1 Roll 1-40, G2 Roll 41-80, G3 Roll 81-Last.');
